// ❌ Nested ternaries — extremely hard to read and extend
function Notification({ type, message }) {
  return (
    <div>
      {type === 'success'
        ? <SuccessCard message={message} />
        : type === 'error'
          ? <ErrorCard message={message} />
          : type === 'warning'
            ? <WarningCard message={message} />
            : type === 'info'
              ? <InfoCard message={message} />
              : <DefaultCard message={message} />}
    </div>
  );
}

function Notification({ type, message }) {
  let card;

  switch (type) {
    case 'success':
      card = <SuccessCard message={message} />;
      break;
    case 'error':
      card = <ErrorCard message={message} />;
      break;
    case 'warning':
      card = <WarningCard message={message} />;
      break;
    case 'info':
      card = <InfoCard message={message} />;
      break;
    default:
      card = <DefaultCard message={message} />;
  }

  return <div className="notification-area">{card}</div>;
}

// Defined outside the component — created once, not on every render
const CARD_MAP = {
  success: (msg) => <SuccessCard message={msg} />,
  error:   (msg) => <ErrorCard message={msg} />,
  warning: (msg) => <WarningCard message={msg} />,
  info:    (msg) => <InfoCard message={msg} />,
};

function Notification({ type, message }) {
  // Look up the renderer, fall back to default if key missing
  const renderCard = CARD_MAP[type] ?? ((msg) => <DefaultCard message={msg} />);
  return <div className="notification-area">{renderCard(message)}</div>;
}

// ✓ Static: element has no props — store JSX directly
const STATUS_ICONS = {
  success: <CheckCircleIcon className="text-green-600" />,
  error:   <XCircleIcon className="text-red-600" />,
  warning: <TriangleAlertIcon className="text-amber-500" />,
  info:    <InfoIcon className="text-blue-500" />,
};

function StatusBadge({ status }) {
  return (
    <span className={`badge badge-${status}`}>
      {STATUS_ICONS[status] ?? STATUS_ICONS.info}
    </span>
  );
}

// ✓ Dynamic: element has variable props — store component reference
const STATUS_COMPONENTS = {
  success: SuccessCard,
  error:   ErrorCard,
  warning: WarningCard,
  info:    InfoCard,
};

function Notification({ type, message, onDismiss }) {
  const CardComponent = STATUS_COMPONENTS[type] ?? DefaultCard;
  return <CardComponent message={message} onDismiss={onDismiss} />;
}

// ✓ Outside — created once
const ROUTE_LABELS = {
  home:     'Home',
  profile:  'My Profile',
  settings: 'Settings',
  help:     'Help Center',
};

function NavItem({ route }) {
  return <a href={`/${route}`}>{ROUTE_LABELS[route] ?? route}</a>;
}

// ❌ Inside — recreated every render
function NavItem({ route }) {
  const routeLabels = {       // new object on every render
    home: 'Home',
    // ...
  };
  return <a href={`/${route}`}>{routeLabels[route] ?? route}</a>;
}

// Inside is necessary when values depend on props
function NavItem({ route, user }) {
  const routeLabels = {
    profile: `${user.firstName}'s Profile`,  // depends on prop
    home: 'Home',
  };
  return <a href={`/${route}`}>{routeLabels[route] ?? route}</a>;
}

type Status = 'success' | 'error' | 'warning' | 'info';

// Record<Status, ...> ensures all four keys are present
const STATUS_COMPONENTS: Record<Status, React.ComponentType<{ message: string }>> = {
  success: SuccessCard,
  error:   ErrorCard,
  warning: WarningCard,
  info:    InfoCard,
  // If you add 'critical' to Status but forget it here,
  // TypeScript will report: Property 'critical' is missing
};

function Notification({ type, message }: { type: Status; message: string }) {
  const CardComponent = STATUS_COMPONENTS[type]; // no fallback needed — TS guarantees key exists
  return <CardComponent message={message} />;
}

// Config array — could come from an API
const PLAN_CONFIG = [
  { id: 'free',       label: 'Free',       icon: '🆓', color: 'gray' },
  { id: 'pro',        label: 'Pro',        icon: '⭐', color: 'blue' },
  { id: 'enterprise', label: 'Enterprise', icon: '🏢', color: 'purple' },
];

// Build a lookup map from the config
const PLAN_BADGE = Object.fromEntries(
  PLAN_CONFIG.map(plan => [
    plan.id,
    <span key={plan.id} className={`badge badge-${plan.color}`}>
      {plan.icon} {plan.label}
    </span>
  ])
);
// PLAN_BADGE['pro'] → <span className="badge badge-blue">⭐ Pro</span>

function UserPlan({ planId }) {
  return PLAN_BADGE[planId] ?? <span className="badge badge-gray">Unknown</span>;
}

// IIFE — technically valid but clutters the return block
function Notification({ type, message }) {
  return (
    <div>
      {(() => {
        switch (type) {
          case 'success': return <SuccessCard message={message} />;
          case 'error':   return <ErrorCard message={message} />;
          default:        return <DefaultCard message={message} />;
        }
      })()}
    </div>
  );
}

// Prefer the element variable form — same logic, cleaner structure
function Notification({ type, message }) {
  let card;
  switch (type) {
    case 'success': card = <SuccessCard message={message} />; break;
    case 'error':   card = <ErrorCard message={message} />;   break;
    default:        card = <DefaultCard message={message} />;
  }
  return <div>{card}</div>;
}

// Lookup map — each step is a component reference
const STEP_COMPONENTS = {
  1: AccountInfoStep,
  2: PlanSelectionStep,
  3: PaymentStep,
  4: ReviewStep,
};

function SignUpWizard({ currentStep, onNext, onBack, formData, setFormData }) {
  const StepComponent = STEP_COMPONENTS[currentStep];

  if (!StepComponent) {
    return <div>Unknown step</div>;
  }

  return (
    <div className="wizard">
      <ProgressBar total={4} current={currentStep} />
      <StepComponent
        formData={formData}
        onChange={setFormData}
        onNext={onNext}
        onBack={onBack}
      />
    </div>
  );
}

import { render, screen } from '@testing-library/react';

describe('Notification', () => {
  test.each([
    ['success', /success card/i],
    ['error',   /error card/i],
    ['warning', /warning card/i],
    ['info',    /info card/i],
  ])('renders %s card for type "%s"', (type, matcher) => {
    render(<Notification type={type} message="Test" />);
    expect(screen.getByRole('alert', { name: matcher })).toBeInTheDocument();
  });

  test('renders default card for unknown type', () => {
    render(<Notification type="unknown" message="Test" />);
    expect(screen.getByText(/unknown notification/i)).toBeInTheDocument();
  });
});

describe('StatusBadge', () => {
  const statuses = ['success', 'error', 'warning', 'info'];

  statuses.forEach(status => {
    test(`renders icon for status ${status}`, () => {
      const { container } = render(<StatusBadge status={status} />);
      expect(container.querySelector('svg')).toBeInTheDocument();
    });
  });
});

import { lazy, Suspense } from 'react';

// Each import() call creates a separate bundle chunk
const PAGE_COMPONENTS = {
  home:     lazy(() => import('./pages/HomePage')),
  profile:  lazy(() => import('./pages/ProfilePage')),
  settings: lazy(() => import('./pages/SettingsPage')),
  help:     lazy(() => import('./pages/HelpPage')),
};

function App({ currentRoute }) {
  const PageComponent = PAGE_COMPONENTS[currentRoute];

  if (!PageComponent) {
    return <NotFoundPage />;
  }

  return (
    <Suspense fallback={<PageSkeleton />}>
      <PageComponent />
    </Suspense>
  );
}

// 1. Nullish coalescing for a static fallback element
const icon = STATUS_ICONS[status] ?? <HelpCircleIcon />;

// 2. Nullish coalescing for a fallback component reference
const CardComponent = STATUS_COMPONENTS[status] ?? DefaultCard;
return <CardComponent message={message} />;

// 3. Guard with early return
function StatusBadge({ status }) {
  const badge = STATUS_BADGES[status];
  if (!badge) return null; // or render an error boundary trigger
  return badge;
}

// 4. 'default' key in the map — explicit and self-documenting
const STATUS_ICONS_WITH_DEFAULT = {
  success: <CheckIcon />,
  error:   <AlertIcon />,
  default: <InfoIcon />,    // used when key is unknown
};
const icon = STATUS_ICONS_WITH_DEFAULT[status]
          ?? STATUS_ICONS_WITH_DEFAULT.default;

function PlanBadge({ plan }) {
  let badgeClass;

  switch (plan) {
    case 'monthly':
    case 'annual':         // fall-through — same badge for both billing cycles
      badgeClass = 'badge-blue';
      break;
    case 'enterprise':
    case 'enterprise-plus': // fall-through
      badgeClass = 'badge-purple';
      break;
    default:
      badgeClass = 'badge-gray';
  }

  return <span className={badgeClass}>{plan}</span>;
}

// Equivalent lookup map — uses array grouping
const PLAN_CLASS_MAP = {
  monthly:          'badge-blue',
  annual:           'badge-blue',
  enterprise:       'badge-purple',
  'enterprise-plus':'badge-purple',
};
const badgeClass = PLAN_CLASS_MAP[plan] ?? 'badge-gray';

const PERMISSION_CONFIG = {
  read:   { label: 'Read',   description: 'View content',           icon: <EyeIcon /> },
  write:  { label: 'Write',  description: 'Create and edit content', icon: <PencilIcon /> },
  admin:  { label: 'Admin',  description: 'Manage team and settings', icon: <ShieldIcon /> },
};

function PermissionTable({ userPermissions }) {
  return (
    <table>
      <thead>
        <tr>
          <th>Permission</th>
          <th>Description</th>
          <th>Granted</th>
        </tr>
      </thead>
      <tbody>
        {Object.entries(PERMISSION_CONFIG).map(([key, config]) => (
          <tr key={key}>
            <td>{config.icon} {config.label}</td>
            <td>{config.description}</td>
            <td>{userPermissions.includes(key) ? '✓' : '—'}</td>
          </tr>
        ))}
      </tbody>
    </table>
  );
}
